import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  static const _authTokenKey = "auth_token";
  static const _userDataKey = "user_data";

  // Get current auth token from shared preferences, if any
  Future<String?> getCurrentAuthToken() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    return prefs.getString(_authTokenKey);
  }

  // Save current auth token and user data to shared preferences
  Future<void> saveAuthToken(String token, dynamic userData) async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    prefs.setString(_authTokenKey, token);
    prefs.setStringList(_userDataKey, jsonEncode(userData));
  }

  // Remove current auth token and user data from shared preferences
  Future<void> clearAuthToken() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    prefs.remove(_authTokenKey);
    prefs.remove(_userDataKey);
  }
}